class Solution:
    def maximumSumOfHeights(self, maxHeights):
        n = len(maxHeights)
        best = 0
        for p in range(n):
            heights = [0] * n
            heights[p] = maxHeights[p]
            for i in range(p - 1, -1, -1):
                heights[i] = min(maxHeights[i], heights[i + 1])
            for i in range(p + 1, n):
                heights[i] = min(maxHeights[i], heights[i - 1])
            best = max(best, sum(heights))
        return best

