class Solution:
    def maximumSumOfHeights(self, maxHeights):
        n = len(maxHeights)
        left = [0] * n
        stack = []
        for i in range(n):
            h = maxHeights[i]
            while stack and maxHeights[stack[-1]] >= h:
                stack.pop()
            if stack:
                j = stack[-1]
                left[i] = left[j] + h * (i - j)
            else:
                left[i] = h * (i + 1)
            stack.append(i)

        right = [0] * n
        stack = []
        for i in range(n - 1, -1, -1):
            h = maxHeights[i]
            while stack and maxHeights[stack[-1]] >= h:
                stack.pop()
            if stack:
                j = stack[-1]
                right[i] = right[j] + h * (j - i)
            else:
                right[i] = h * (n - i)
            stack.append(i)

        return max(left[i] + right[i] - maxHeights[i] for i in range(n))

