var maximumSumOfHeights = function(maxHeights) {
    const n = maxHeights.length;
    const left = new Array(n).fill(0);
    let stack = [];
    for (let i = 0; i < n; i++) {
        const h = maxHeights[i];
        while (stack.length && maxHeights[stack[stack.length - 1]] >= h) stack.pop();
        if (stack.length) {
            const j = stack[stack.length - 1];
            left[i] = left[j] + h * (i - j);
        } else {
            left[i] = h * (i + 1);
        }
        stack.push(i);
    }
    const right = new Array(n).fill(0);
    stack = [];
    for (let i = n - 1; i >= 0; i--) {
        const h = maxHeights[i];
        while (stack.length && maxHeights[stack[stack.length - 1]] >= h) stack.pop();
        if (stack.length) {
            const j = stack[stack.length - 1];
            right[i] = right[j] + h * (j - i);
        } else {
            right[i] = h * (n - i);
        }
        stack.push(i);
    }
    let best = 0;
    for (let i = 0; i < n; i++) best = Math.max(best, left[i] + right[i] - maxHeights[i]);
    return best;
};
